# ── 页面2 Treeview 交互逻辑 ──

def reapply_treeview_tags():
    """重新应用奇偶行标签"""
    for idx, item in enumerate(treeview_1.get_children()):
        tag = "evenrow" if idx % 2 == 0 else "oddrow"
        treeview_1.item(item, tags=(tag,))


def toggle_checkbox(event):
    """点击第一列切换勾选状态"""
    region = treeview_1.identify("region", event.x, event.y)
    if region != "cell":
        return
    column = treeview_1.identify_column(event.x)
    if column != "#1":
        return
    iid = treeview_1.identify_row(event.y)
    if not iid:
        return

    current = treeview_1.set(iid, "选中")
    if current == "☑":
        treeview_1.set(iid, "选中", "☐")
    else:
        treeview_1.set(iid, "选中", "☑")


def toggle_select_all(event=None):
    """点击表头第一列：全选/取消全选"""
    all_items = treeview_1.get_children()
    if not all_items:
        return

    # 判断当前是否全部勾选
    all_checked = all(treeview_1.set(item, "选中") == "☑" for item in all_items)

    new_state = "☐" if all_checked else "☑"
    for item in all_items:
        treeview_1.set(item, "选中", new_state)


def on_double_click_edit(event):
    """双击单元格进入编辑模式（第一列除外）"""
    region = treeview_1.identify("region", event.x, event.y)
    if region != "cell":
        return
    column = treeview_1.identify_column(event.x)
    if column == "#1":
        return  # 第一列是checkbox，不可编辑
    iid = treeview_1.identify_row(event.y)
    if not iid:
        return

    col_index = int(column[1:]) - 1
    col_name = treeview_1_cols[col_index]

    # 获取单元格坐标 (相对于 Treeview)
    bbox = treeview_1.bbox(iid, column)
    if not bbox:
        return
    x_cell, y_cell, w_cell, h_cell = bbox

    current_value = treeview_1.set(iid, col_name)

    # 在 page_frame_2 上定位 Entry（Treeview 在 page_frame_2 的 x=6, y=10）
    edit_entry = Entry(
        page_frame_2,
        font=("Inter", 13),
        bd=1,
        relief="solid",
        justify="center"
    )
    edit_entry.place(x=6 + x_cell, y=10 + y_cell, width=w_cell, height=h_cell)
    edit_entry.insert(0, current_value)
    edit_entry.select_range(0, "end")
    edit_entry.focus_set()

    _editing_done = False

    def save_edit(event=None):
        nonlocal _editing_done
        if _editing_done:
            return
        _editing_done = True
        new_value = edit_entry.get()
        values = list(treeview_1.item(iid, "values"))
        values[col_index] = new_value
        treeview_1.item(iid, values=values)
        edit_entry.destroy()
        # UID 列编辑后，若昵称为空则自动查询补全
        if col_index == 1 and new_value.strip() and not values[2]:
            _debug(f"自动补全触发: {new_value.strip()}")
            _auto_fill_name(iid, new_value.strip())

    edit_entry.bind("<Return>", save_edit)
    edit_entry.bind("<FocusOut>", save_edit)


def add_new_row():
    """新增空白行"""
    all_items = treeview_1.get_children()
    idx = len(all_items)
    tag = "evenrow" if idx % 2 == 0 else "oddrow"
    treeview_1.insert("", "end", values=["☐", "", ""], tags=(tag,))


def _auto_fill_name(iid, uid):
    """异步查询 B站 API 补全昵称"""
    import threading
    def fetch():
        try:
            name = fetch_up_name(uid)
            if name:
                window.after(0, lambda: _set_name(iid, name))
            else:
                _debug(f"自动补全: {uid} 未查到昵称")
        except Exception as e:
            _debug(f"自动补全失败: {uid} -> {e}")
    threading.Thread(target=fetch, daemon=True).start()


def _set_name(iid, name):
    """在主线程中设置 Treeview 昵称列"""
    values = list(treeview_1.item(iid, "values"))
    values[2] = name
    treeview_1.item(iid, values=values)


def delete_selected():
    """删除所有勾选的行"""
    to_delete = []
    for item in treeview_1.get_children():
        if treeview_1.set(item, "选中") == "☑":
            to_delete.append(item)

    if not to_delete:
        messagebox.showinfo("提示", "没有选中任何行")
        return

    if not messagebox.askyesno("确认删除", f"确定删除选中的 {len(to_delete)} 行吗？"):
        return

    for item in to_delete:
        treeview_1.delete(item)
    reapply_treeview_tags()


# ============================================================
#  托盘功能
# ============================================================
_tray_icon = None
_should_exit = False
_handling_minimize = False


def _create_tray_image():
    """生成托盘图标（64x64 红色K线风格）"""
    img = Image.new('RGBA', (64, 64), (0, 0, 0, 0))
    draw = ImageDraw.Draw(img)
    draw.rectangle([8, 8, 56, 56], fill=(178, 34, 34), outline=(128, 0, 0), width=2)
    draw.line([(20, 42), (30, 26), (38, 36), (48, 20)], fill=(255, 255, 255), width=4)
    return img


def _restore_window(icon, item=None):
    """从托盘恢复主窗口（不销毁托盘图标，图标始终驻留）"""
    global _handling_minimize
    _handling_minimize = False
    window.deiconify()
    window.state('normal')
    window.lift()
    window.focus_force()


def _quit_app(icon, item=None):
    """彻底退出程序"""
    global _tray_icon, _should_exit
    _should_exit = True
    if _tray_icon:
        _tray_icon.stop()
        _tray_icon = None
    try:
        valley_scheduler.stop()
    except Exception:
        pass
    window.destroy()


def _hide_to_tray():
    """窗口最小化到托盘（托盘图标始终存在）"""
    if not HAS_TRAY:
        return
    window.withdraw()


def _init_tray_icon():
    """程序启动时即显示托盘图标，不隐藏窗口"""
    global _tray_icon
    if not HAS_TRAY:
        return
    if _tray_icon is not None:
        return
    menu = pystray.Menu(
        pystray.MenuItem('显示', _restore_window, default=True),
        pystray.MenuItem('退出', _quit_app),
    )
    _tray_icon = pystray.Icon('bilidigest', _create_tray_image(), 'BiliDigest', menu)
    threading.Thread(target=_tray_icon.run, daemon=True).start()


def _on_window_close():
    """关闭窗口时最小化到托盘"""
    if _should_exit:
        _quit_app(None)
        return
    _hide_to_tray()


def _on_unmap(event):
    """捕获最小化事件"""
    global _handling_minimize
    if _handling_minimize or _should_exit:
        return
    if event.widget is window and window.state() == 'iconic':
        _handling_minimize = True
        _hide_to_tray()


